#include <iostream>\n#include <cstdint>\n#include <vector>\n\nclass Graph {\n public:\n  Graph(size_t n, std::vector<std::pair<size_t, size_t>> edges) {\n    table_.resize(n + 1);\n    visited_.resize(n + 1);\n    Build(edges);\n  }\n\n  size_t GetCompsCount() {\n    for (size_t i = 1; i < visited_.size(); i++) {\n      if (!visited_[i]) {\n        Dfs(i);\n        comps_count_++;\n      }\n    }\n    return comps_count_;\n  }\n\n private:\n  void Build(const std::vector<std::pair<size_t, size_t>>& edges) {\n    for (const std::pair<size_t, size_t>& pair : edges) {\n      auto i = pair.first;\n      auto j = pair.second;\n      table_[i].push_back(j);\n      table_[j].push_back(i);\n    }\n  }\n\n  void Dfs(size_t start) {\n    visited_[start] = true;\n    const std::vector<size_t>& children = table_[start];\n    for (auto i : children) {\n      if (!visited_[i]) {\n        Dfs(i);\n      }\n    }\n  }\n\n  size_t comps_count_ = 0;\n  std::vector<std::vector<size_t>> table_;\n  std::vector<bool> visited_;\n};\n\nint main() {\n  size_t m = 0;\n  std::cin >> m;\n  std::vector<std::pair<size_t, size_t>> edges(m);\n  for (size_t it = 0; it < m; it++) {\n    size_t j = 0;\n    std::cin >> j;\n    edges[it] = {it + 1, j};\n  }\n\n  Graph graph(m, edges);\n  auto comps = graph.GetCompsCount();\n\n  std::cout << comps << std::endl;\n  return 0;\n}